import{_ as s,o as a,c as i,ae as t}from"./chunks/framework.BGHOrOyn.js";const g=JSON.parse('{"title":"Run docker without needing sudo","description":"","frontmatter":{},"headers":[],"relativePath":"snippets-and-scripts/scripts/run-docker-without-needing-sudo.md","filePath":"snippets-and-scripts/scripts/run-docker-without-needing-sudo.md"}'),n={name:"snippets-and-scripts/scripts/run-docker-without-needing-sudo.md"};function o(r,e,d,l,p,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="run-docker-without-needing-sudo" tabindex="-1">Run docker without needing sudo <a class="header-anchor" href="#run-docker-without-needing-sudo" aria-label="Permalink to &quot;Run docker without needing sudo&quot;">​</a></h1><p>To create the <code>docker</code> group and add your user:</p><ol><li><p>Create the <code>docker</code> group.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ sudo groupadd docker</span></span></code></pre></div></li><li><p>Add your user to the <code>docker</code> group.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ sudo usermod -aG docker $USER</span></span></code></pre></div></li><li><p>Log out and log back in so that your group membership is re-evaluated.</p><blockquote><p>If you’re running Linux in a virtual machine, it may be necessary to restart the virtual machine for changes to take effect.</p></blockquote><p>You can also run the following command to activate the changes to groups:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ newgrp docker</span></span></code></pre></div></li><li><p>Verify that you can run <code>docker</code> commands without <code>sudo</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ docker run hello-world</span></span></code></pre></div><p>This command downloads a test image and runs it in a container. When the container runs, it prints a message and exits.</p><p>If you initially ran Docker CLI commands using <code>sudo</code> before adding your user to the <code>docker</code> group, you may see the following error:</p><div class="language-none vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">none</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WARNING: Error loading config file: /home/user/.docker/config.json -</span></span>
<span class="line"><span>stat /home/user/.docker/config.json: permission denied</span></span></code></pre></div></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>    This error indicates that the permission settings for the \`~/.docker/\` directory are incorrect, due to having used the \`sudo\` command earlier.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    To fix this problem, either remove the \`~/.docker/\` directory (it’s recreated automatically, but any custom settings are lost), or change its ownership and permissions using the following commands:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`php</span></span>
<span class="line"><span>    $ sudo chown &quot;$USER&quot;:&quot;$USER&quot; /home/&quot;$USER&quot;/.docker -R</span></span>
<span class="line"><span>    $ sudo chmod g+rwx &quot;$HOME/.docker&quot; -R</span></span></code></pre></div><h2 id="configure-docker-to-start-on-boot-with-systemd" tabindex="-1">Configure Docker to start on boot with systemd <a class="header-anchor" href="#configure-docker-to-start-on-boot-with-systemd" aria-label="Permalink to &quot;Configure Docker to start on boot with systemd&quot;">​</a></h2><p>Many modern Linux distributions use <a href="https://docs.docker.com/config/daemon/systemd/" target="_blank" rel="noreferrer">systemd</a> to manage which services start when the system boots. On Debian and Ubuntu, the Docker service starts on boot by default. To automatically start Docker and containerd on boot for other Linux distributions using systemd, run the following commands:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> docker</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">service</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> containerd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">service</span></span></code></pre></div><p>To stop this behavior, use <code>disable</code> instead.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> disable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> docker</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">service</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> disable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> containerd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">service</span></span></code></pre></div><p>If you need to add an HTTP proxy, set a different directory or partition for the Docker runtime files, or make other customizations, see <a href="https://docs.docker.com/config/daemon/systemd/" target="_blank" rel="noreferrer">customize your systemd Docker daemon options</a>.</p><h3 id="configure-default-logging-driver" tabindex="-1">Configure default logging driver <a class="header-anchor" href="#configure-default-logging-driver" aria-label="Permalink to &quot;Configure default logging driver&quot;">​</a></h3><p>Docker provides <a href="https://docs.docker.com/config/containers/logging/" target="_blank" rel="noreferrer">logging drivers</a> for collecting and viewing log data from all containers running on a host. The default logging driver, <code>json-file</code>, writes log data to JSON-formatted files on the host filesystem. Over time, these log files expand in size, leading to potential exhaustion of disk resources.</p><p>To avoid issues with overusing disk for log data, consider one of the following options:</p><ul><li>Configure the <code>json-file</code> logging driver to turn on <a href="https://docs.docker.com/config/containers/logging/json-file/" target="_blank" rel="noreferrer">log rotation</a></li><li>Use an <a href="https://docs.docker.com/config/containers/logging/configure/#configure-the-default-logging-driver" target="_blank" rel="noreferrer">alternative logging driver</a> such as the <a href="https://docs.docker.com/config/containers/logging/local/" target="_blank" rel="noreferrer">“local” logging driver</a> that performs log rotation by default</li><li>Use a logging driver that sends logs to a remote logging aggregator.</li></ul><h3 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h3><ul><li>Take a look at the <a href="https://docs.docker.com/get-started/" target="_blank" rel="noreferrer">Get started</a> training modules to learn how to build an image and run it as a containerized application.</li><li>Review the topics in <a href="https://docs.docker.com/develop/" target="_blank" rel="noreferrer">Develop with Docker</a> to learn how to build new applications using Docker.</li></ul>`,16)])])}const u=s(n,[["render",o]]);export{g as __pageData,u as default};
